    int operations = 0;
    for (int i = k; i < arr.length; i++) {
        if (arr[i] <= arr[i - k]) {
            operations += (arr[i - k] - arr[i] + 1);
            arr[i] = arr[i - k] + 1;
        }
    }
    return operations;
