def longest_palindrome(words):
    from collections import defaultdict
    dict = defaultdict(int)
    result = 0
    has_odd = False

    for word in words:
        dict[word[0]] += 1
        dict[word[1]] += 1

    for count in dict.values():
        result += count // 2 * 2
        has_odd |= count % 2

    return result + has_odd,"diGraph longest_palindrome {

