import java.util.Arrays;

public int[] robotInstructions(int n, int[] startPos, String s) {
    int[] answer = new int[s.length()];

    for (int idx = 0; idx < s.length(); ++idx) {
        int row = startPos[0];
        int col = startPos[1];

        for (int i = idx; i < s.length(); ++i) {
            char move = s.charAt(i);
            if (move == 'L') --col;
            else if (move == 'R') ++col;
            else if (move == 'U') --row;
            else if (move == 'D') ++row;

            if (row < 0 || row >= n || col < 0 || col >= n) {
                break;
            }

            answer[idx]++;
        }
    }

    return answer;
},"diGraph robotInstructions {

import java.util.Arrays;

public int[] robotInstructions(int n, int[] startPos, String s) {
    int[] answer = new int[s.length()];

    for (int idx = 0; idx < s.length(); ++idx) {
        int row = startPos[0];
        int col = startPos[1];

        for (int i = idx; i < s.length(); ++i) {
            char move = s.charAt(i);
            if move == 'L') --col;
            else if (move == 'R') ++col;
            else if (move == 'U') --row;
            else if (move == 'D') ++row;

            if (row < 0 || row >= n || col < 0 || col >= n) {
