public int maxInvites(int[] favorite) {
    int n = favorite.length;
    int[] dp = new int[n];
    int maxInvites = 0;

    for (int i = 0; i < n; i++) {
        dp[i] = (i == favorite[favorite[i]]) ? 2 : 1;
        maxInvites = Math.max(maxInvites, dp[i]);
    }

    return maxInvites;
