public int minCost(int[] cost) {
    Arrays.sort(cost);
    int n = cost.length;
    int min_cost = 0;

    for(int i = n - 1; i >= 0; i -= 3) {
        min_cost += cost[i];
        if(i - 1 >= 0) min_cost += cost[i - 1];
    }

    return min_cost;
},"diGraph minCost {

