public int minSwaps(int[] nums) {
    int ones = 0, maxOnes = 0, currOnes = 0, left = 0;

    for (int num : nums) {
        ones += num;
    }

    for (int right = 0; right < nums.length; ++right) {
        currOnes += nums[right];

        if (right - left + 1 > ones) {
            currOnes -= nums[left];
            ++left;
        }

        maxOnes = Math.max(maxOnes, currOnes);
    }

    return ones - maxOnes;
},"diGraph minSwaps {

