public ArrayList<String> partitionString(String s, int k, char fill) {
    ArrayList<String> partitions = new ArrayList<>();
    StringBuilder currentPartition = new StringBuilder();
    for(char c : s.toCharArray()) {
        currentPartition.append(c);
        if(currentPartition.length() == k) {
            partitions.add(currentPartition.toString());
            currentPartition.setLength(0); // clear the contents
        }
    }
    if(currentPartition.length() != 0) {
        while(currentPartition.length() < k) {
            currentPartition.append(fill);
        }
        partitions.add(currentPartition.toString());
    }
    return partitions;
},"diGraph partitionString {

