public int maxPoints(int[][] questions) {
    int n = questions.length;
    int[] dp = new int[n + 1];

    for (int i = n - 1; i >= 0; i--) {
        int skip_next = i + questions[i][1];
        dp[i] = Math.max(dp[i + 1], questions[i][0] + (skip_next < n ? dp[skip_next] : 0));
    }

    return dp[0];
},"diGraph maxPoints {

