public int minCost(int startAt, int moveCost, int pushCost, int targetSeconds) {
    int min_cost = Integer.MAX_VALUE;

    for (int i = 0; i <= 99; i++) {
        for (int j = 0; j <= 99; j++) {
            if (i * 60 + j == targetSeconds) {
                int minute_move_cost = Math.abs(i - startAt) * moveCost;
                int second_move_cost = Math.abs(j - i) * moveCost;
                int total_push_cost = (j > 0 ? 2 : 0) + (j / 10 != 0 ? 1 : 0) + (i / 10 != 0 ? 1 : 0);

                min_cost = Math.min(min_cost, minute_move_cost + second_move_cost + total_push_cost * pushCost);
            }
        }
    }
    return min_cost;
},"diGraph minCost {

