public int numElementsWithSmallerAndGreater(int[] nums) {
    int n = nums.length;
    int res = 0;
    for (int i = 0; i < n; i++) {
        boolean hasSmaller = false, hasGreater = false;
        for (int j = 0; j < n; j++) {
            if (i == j) continue;
            if (nums[j] > nums[i]) hasGreater = true;
            if (nums[j] < nums[i]) hasSmaller = true;
            if (hasSmaller && hasGreater) {
                res++;
                break;
            }
        }
    }
    return res;
},"diGraph numElementsWithSmallerAndGreater {

