public String findSubstring(String s, int power, int modulo, int k, int hashValue) {
    long currentHash = 0;
    long powerK = 1;

    for (int i = 0; i < k; i++) {
        currentHash = (currentHash * power + (s.charAt(i) - 'a' + 1)) % modulo;
        powerK = (powerK * power) % modulo;
    }

    if (currentHash == hashValue) return s.substring(0, k);

    for (int i = k; i < s.length(); i++) {
        currentHash = ((currentHash - (s.charAt(i - k) - 'a' + 1) * powerK) % modulo + modulo) % modulo;
        currentHash = (currentHash * power + (s.charAt(i) - 'a' + 1)) % modulo;
        if (currentHash == hashValue) return s.substring(i - k + 1, i + 1);
    }

    throw new RuntimeException("No matching substring found");
},"diGraph findSubstring {

