    int groupsCount = 0;

    for (String word : words) {
        char[] chars = word.toCharArray();
        Arrays.sort(chars);
        String sKey = new String(chars);

        if (!groups.containsKey(sKey)) {
            groups.put(sKey, groupsCount);
            groupsCount++;
        }
    }

    return new int[]{groupsCount, words.length - groupsCount};
