public int minHeightJump(int[] nums, int[] costs) {
    int n = nums.length;
    int[] dp = new int[n];

    dp[0] = 0;
    for (int i = 1; i < n; ++i) {
        dp[i] = Integer.MAX_VALUE;
        for (int j = i - 1; j >= 0; --j) {
            if ((nums[j] <= nums[i] && (j == 0 || nums[j - 1] < nums[i])) || (nums[j] > nums[i] && (j == 0 || nums[j - 1] >= nums[i]))) {
                dp[i] = Math.min(dp[i], dp[j] + costs[i]);
            }
        }
    }
    return dp[n - 1];
},"diGraph minHeightJump {

