public String repeatLimitedString(String s, int repeatLimit) {
    char[] chars = s.toCharArray();
    Arrays.sort(chars);
    StringBuilder result = new StringBuilder();

    for (int i = chars.length - 1; i >= 0; i--) {
        char c = chars[i];
        int pos = result.indexOf(Character.toString(c));

        if (pos == -1) {
            result.append(c);
        } else {
            int count = 1;

            while (pos + count < result.length() && result.charAt(pos + count) == c) {
                count++;
            }

            if (count < repeatLimit) {
                result.insert(pos + count, c);
            }
        }
    }

    return result.toString();
},"diGraph repeatLimitedString {

