public int countSubarrays(int[] nums, long k) {
    int n = nums.length;
    int left = 0, right = 0;
    long sum = 0, count = 0;

    while (right < n) {
        sum += nums[right];
        while (sum * (right - left + 1) >= k) {
            sum -= nums[left];
            left++;
        }
        count += right - left + 1;
        right++;
    }

    return (int)count;
},"diGraph countSubarrays {

