    double tax = 0;
    int prev_upper = 0;
    for (int[] bracket : brackets) {
        int upper = bracket[0];
        double percent = bracket[1] / 100.0;
        tax += (Math.min(upper, income) - prev_upper) * percent;
        prev_upper = upper;
        if (income <= upper) break;
    }
    return tax;
