    int n = s.length();
    int sumScores = 0;
    int longestCommonPrefix = 0;
    for (int i = n - 1; i >= 0; i--) {
        if (s.charAt(i) == s.charAt(n - 1 - longestCommonPrefix)) {
            longestCommonPrefix++;
        } else {
            longestCommonPrefix = 0;
        }
        sumScores += longestCommonPrefix;
    }
    return sumScores;
