    num_str = str(num)
    even_digits = sorted([c for c in num_str if int(c) % 2 == 0], reverse=True)
    odd_digits = sorted([c for c in num_str if int(c) % 2 == 1], reverse=True)

    result = []
    for c in num_str:
        if int(c) % 2 == 0:
