public boolean evalTree(TreeNode root) {
    if (root.left == null && root.right == null)
        return root.val == 1;
    boolean left = evalTree(root.left);
    boolean right = evalTree(root.right);

    if (root.val == 2)
        return left || right;
    return left && right;
},"diGraph evalTree {

