public int lastPassengerTime(int[] buses, int[] passengers, int capacity) {
    Arrays.sort(buses);
    Arrays.sort(passengers);

    int lastIndex = 0;
    for (int bus : buses) {
        int cnt = 0;
        while (lastIndex < passengers.length && passengers[lastIndex] <= bus && cnt < capacity) {
            cnt++;
            lastIndex++;
        }
    }

    return lastIndex == 0 ? buses[0] - 1 : passengers[lastIndex - 1] - 1;
},"diGraph lastPassengerTime {

