public int countEqualRowColumnPairs(int[][] grid) {
    int n = grid.length;
    int ans = 0;

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            boolean equal = true;
            for (int k = 0; k < n; ++k) {
                if (grid[i][k] != grid[k][j]) {
                    equal = false;
                    break;
                }
            }
            if (equal) {
                ++ans;
            }
        }
    }

    return ans;
},"diGraph countEqualRowColumnPairs {

