int max_groups(int[] grades) {
    int len = grades.length;
    int[] dp = new int[len];
    Arrays.fill(dp, 1);

    Arrays.sort(grades);

    for (int i = 0; i < len; ++i) {
        for (int j = 0; j < i; ++j) {
            if (grades[i] + dp[j] * grades[j] > (i+1) * grades[j]) {
                dp[i] = dp[j] + 1;
            }
        }
    }

    return dp[len - 1];
