public int findLongestCycle(int[] edges) {
    int n = edges.length;
    boolean[] visited = new boolean[n];
    int longest_cycle = -1;

    for (int i = 0; i < n; ++i) {
        if (!visited[i]) {
            int length = 0;
            int node = i;

            while (!visited[node] && edges[node] != -1) {
                visited[node] = true;
                length++;
                node = edges[node];
            }

            if (edges[node] == i) {
                longest_cycle = Math.max(longest_cycle, length);
            }
        }
    }

    return longest_cycle;
},"diGraph findLongestCycle {

