public int minDaysToCompleteTasks(int[] tasks, int space) {
    HashMap<Integer, Integer> taskLastComplete = new HashMap<>();
    int days = 0;

    for (int task : tasks) {
        if (taskLastComplete.containsKey(task)) {
            int passedDays = days - taskLastComplete.get(task);
            if (passedDays < space) {
                days += space - passedDays;
            }
        }
        days++;
        taskLastComplete.put(task, days);
    }

    return days;
},"diGraph minDaysToCompleteTasks {

