public int longestIdealString(String s, int k) {
    int[] dp = new int[26];

    for (char c : s.toCharArray()) {
        int current = 1;
        for (int i = 0; i < 26; ++i) {
            if (Math.abs(i - (c - 'a')) <= k)
                current = Math.max(current, dp[i] + 1);
        }
        dp[c - 'a'] = Math.max(dp[c - 'a'], current);
    }

    int max = 0;
    for (int value : dp) {
        max = Math.max(max, value);
    }

    return max;
},"diGraph longestIdealString {

