boolean isDistinct(int n) {
    Set<Integer> uniqueDigits = new HashSet<>();
    while (n > 0) {
        int digit = n % 10;
        if (uniqueDigits.contains(digit)) {
            return false;
        }
        uniqueDigits.add(digit);
        n /= 10;
    }
    return true;
}

int countSpecial(int n) {
    int count = 0;
    for (int i = 1; i <= n; i++) {
        if (isDistinct(i)) {
            count++;
        }
    }
    return count;
},"diGraph isDistinct {

