public int findMedian(int[][] grid) {
    int m = grid.length, n = grid[0].length;
    int low = 1, high = 1000000;

    while (low < high) {
        int mid = low + (high - low) / 2;
        int count = 0;
        for (int i = 0; i < m; ++i) {
            count += countElements(grid[i], mid);
        }

        if (count < (m * n) / 2 + 1) {
            low = mid + 1;
        } else {
            high = mid;
        }
    }

    return low;
}

private int countElements(int[] row, int value) {
    int left = 0, right = row.length;

    while (left < right) {
        int mid = left + (right - left) / 2;

        if (row[mid] <= value) {
            left = mid + 1;
        } else {
            right = mid;
        }
    }

    return left;
},"diGraph findMedian {

