public int maxCoveredRows(int[][] matrix, int numSelect) {
    int m = matrix.length;
    int n = matrix[0].length;
    int maxCovered = 0;

    for (int i = 0; i < (1 << n); ++i) {
        if (Integer.bitCount(i) == numSelect) {
            int covered = 0;
            for (int row = 0; row < m; ++row) {
                for (int col = 0; col < n; ++col) {
                    if ((matrix[row][col] == 1) && ((i & (1 << col)) > 0)) {
                        covered++;
                        break;
                    }
                }
            }
            maxCovered = Math.max(maxCovered, covered);
        }
    }
    return maxCovered;
},"diGraph maxCoveredRows {

