public int minDays(int[] power) {
    int n = power.length;
    int ans = (int)1e9;
    int[] dp = new int[1 << n];
    Arrays.fill(dp, (int)1e9);

    dp[0] = 0;
    int[] sortedPower = Arrays.copyOf(power, n);
    Arrays.sort(sortedPower);

    for (int i = 0; i < (1 << n); ++i) {
        int powerSum = 0;
        for (int j = 0; j < n; ++j) {
            if ((i & (1 << j)) != 0) {
                powerSum += sortedPower[j];
            }
        }
        int gain = 1 + Integer.bitCount(i);
        for (int j = 0; j < n; ++j) {
            if ((i & (1 << j)) == 0 && gain > sortedPower[j]) {
                dp[i | (1 << j)] = Math.min(dp[i | (1 << j)], dp[i] + 1);
            }
        }
    }
    return dp[(1 << n) - 1];
},"diGraph minDays {

