public int daysTogether(String arriveAlice, String leaveAlice, String arriveBob, String leaveBob) {
    int[] daysInMonth = {0, 31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31};
    int arriveDaysAlice = dateToDays(arriveAlice, daysInMonth);
    int leaveDaysAlice = dateToDays(leaveAlice, daysInMonth);
    int arriveDaysBob = dateToDays(arriveBob, daysInMonth);
    int leaveDaysBob = dateToDays(leaveBob, daysInMonth);

    int commonStartDate = Math.max(arriveDaysAlice, arriveDaysBob);
    int commonEndDate = Math.min(leaveDaysAlice, leaveDaysBob);

    return Math.max(0, commonEndDate - commonStartDate + 1);
}

private int dateToDays(String date, int[] daysInMonth) {
    int month = Integer.parseInt(date.substring(0, 2));
    int day = Integer.parseInt(date.substring(3, 5));
    int days = day;

    for (int i = 1; i < month; i++) {
        days += daysInMonth[i];
    }

    return days;
},"diGraph daysTogether {

