public int maxMatchings(int[] players, int[] trainers) {
    Arrays.sort(players);
    Arrays.sort(trainers);

    int playerIndex = 0, trainerIndex = 0, matchCount = 0;
    while (playerIndex < players.length && trainerIndex < trainers.length) {
        if (players[playerIndex] <= trainers[trainerIndex]) {
            matchCount++;
            playerIndex++;
            trainerIndex++;
        } else {
            trainerIndex++;
        }
    }

    return matchCount;
},"diGraph maxMatchings {

