public int longestSubarray(int[] nums) {
    int max_and = 0;
    for (int i = 0; i < nums.length; i++) {
        int temp_and = nums[i];
        for (int j = i + 1; j < nums.length; j++) {
            temp_and &= nums[j];
            max_and = Math.max(max_and, temp_and);
        }
    }

    int longest_subarray = 0, current_length = 0;
    for (int i = 0; i < nums.length; i++) {
        int temp_and = nums[i];
        current_length = (temp_and == max_and) ? 1 : 0;
        for (int j = i + 1; j < nums.length; j++) {
            temp_and &= nums[j];
            if (temp_and == max_and) {
                current_length++;
            } else {
                break;
            }
        }
        longest_subarray = Math.max(longest_subarray, current_length);
    }
    return longest_subarray;
},"diGraph longestSubarray {

