public int minOperations(int[] nums) {
    int n = nums.length;
    int i = 0, j = n - 1;
    int operations = 0;

    while (i < j) {
        if (nums[i] == nums[j]) {
            i++;
            j--;
        } else if (nums[i] < nums[j]) {
            nums[i + 1] += nums[i];
            i++;
            operations++;
        } else {
            nums[j - 1] += nums[j];
            j--;
            operations++;
        }
    }
    return operations;
},"diGraph minOperations {

