public int commonFactors(int a, int b) {
    int gcd = gcd(a, b);
    int count = 0;
    for (int i = 1; i * i <= gcd; i++) {
        if (gcd % i == 0) {
            count++;
            if (i * i != gcd)
                count++;
        }
    }
    return count;
}

private int gcd(int a, int b) {
    return b == 0 ? a : gcd(b, a % b);
