public int minSetXor(int num1, int num2) {
    int set_count = Integer.bitCount(num2);
    int x = 0;
    for (int i = 0; set_count > 0 && i < 32; i++) {
        if ((num2 >> i) & 1) {
            x |= (1 << i);
            set_count--;
        }
    }
    return x ^ num1;
},"diGraph minSetXor {

