public int maxOperations(String s) {
    int count = 0;
    while (!s.isEmpty()) {
        for (int i = s.length() / 2; i > 0; i--) {
            if (s.substring(0, i).equals(s.substring(i, 2 * i))) {
                s = s.substring(i);
                count++;
                break;
            } else if (i == 1) {
                s = s.substring(1);
                count++;
            }
        }
    }
    return count;
},"diGraph maxOperations {

