public int maxTastiness(int[] price, int[] tastiness, int maxAmount, int maxCoupons) {
    int n = price.length;
    int[][][] dp = new int[n + 1][maxAmount + 1][maxCoupons + 1];

    for (int i = 1; i <= n; i++) {
        int fruit_price = price[i - 1];
        int fruit_tastiness = tastiness[i - 1];
        int half_fruit_price = fruit_price / 2;

        for (int j = 0; j <= maxAmount; j++) {
            for (int k = 0; k <= maxCoupons; k++) {
                dp[i][j][k] = dp[i - 1][j][k];
                if (j >= fruit_price) {
                    dp[i][j][k] = Math.max(dp[i][j][k], dp[i - 1][j - fruit_price][k] + fruit_tastiness);
                }
                if (k > 0 && j >= half_fruit_price) {
                    dp[i][j][k] = Math.max(dp[i][j][k], dp[i - 1][j - half_fruit_price][k - 1] + fruit_tastiness);
                }
            }
        }
    }

    return dp[n][maxAmount][maxCoupons];
},"diGraph maxTastiness {

