    Set<Integer> distinct = new HashSet<>();
    for (int num : nums) {
        distinct.add(num);
        int reversed = 0;
        while (num > 0) {
            reversed = reversed * 10 + num % 10;
            num /= 10;
        }
        distinct.add(reversed);
    }
    return distinct.size();
},"diGraph distinctIntegersAfterReversingAndAdding {

