import java.util.ArrayList;
import java.util.List;

public String stringWithDifferentDifference(String[] words) {
    List<List<Integer>> diffArrays = new ArrayList<>();
    for (String word : words) {
        diffArrays.add(getDifferenceArray(word));
    }

    int oddArrayIndex = -1;
    for (int i = 1; i < diffArrays.size(); i++) {
        int matchCount = 0;
        for (int j = 0; j < diffArrays.get(i).size(); j++) {
            if (diffArrays.get(0).get(j) == diffArrays.get(i).get(j)) {
                matchCount++;
            }
        }

        if (matchCount == 0) {
            oddArrayIndex = i;
            break;
        }
    }

    return words[oddArrayIndex];
}

private List<Integer> getDifferenceArray(String word) {
    List<Integer> differenceArray = new ArrayList<>();
    for (int i = 1; i < word.length(); i++) {
        differenceArray.add(word.charAt(i) - word.charAt(i - 1));
    }
    return differenceArray;
},"diGraph stringWithDifferentDifference {

