public int countDifferences(String a, String b) {
    int diff = 0;
    for (int i = 0; i < a.length(); ++i) {
        if (a.charAt(i) != b.charAt(i)) {
            ++diff;
        }
    }
    return diff;
}

public List<String> findMatchingWords(String[] queries, String[] dictionary) {
    ArrayList<String> result = new ArrayList<>();
    for (String query : queries) {
        for (String dictWord : dictionary) {
            if (countDifferences(query, dictWord) <= 2) {
                result.add(query);
                break;
            }
        }
    }
    return result;
},"diGraph countDifferences {

