int minSeededValue(int[] nums, int space) {
    Map<Integer, Integer> count = new HashMap<>();
    for (int num : nums) {
        count.put(num % space, count.getOrDefault(num % space, 0) + 1);
    }
    return Collections.max(count.entrySet(), (a, b) -> {
            if (a.getValue() < b.getValue()) {
                return -1;
            } else if (a.getValue() > b.getValue()) {
                return 1;
            } else { // a.getValue() == b.getValue()
                return Integer.compare(b.getKey(), a.getKey());
            }
        }).getKey();
},"diGraph minSeededValue {

