public int maxSubarraySumWithDistinctElements(int[] nums, int k) {
    int max_sum = 0, window_sum = 0;
    HashMap<Integer, Integer> freq_map = new HashMap<>();

    for (int i = 0; i < nums.length; i++) {
        freq_map.put(nums[i], freq_map.getOrDefault(nums[i], 0) + 1);
        window_sum += nums[i];
        if (i >= k) {
            freq_map.put(nums[i - k], freq_map.get(nums[i - k]) - 1);
            window_sum -= nums[i - k];
        }
        if (i >= k - 1) {
            boolean is_distinct = true;
            for (Integer value : freq_map.values()) {
                if (value > 1) {
                    is_distinct = false;
                    break;
                }
            }
            if (is_distinct) {
                max_sum = Math.max(max_sum, window_sum);
            }
        }
    }
    return max_sum;
},"diGraph maxSubarraySumWithDistinctElements {

