public int findPivot(int n) {
    int sum = n * (n + 1) / 2;
    int left_sum = 0;
    for (int x = 1; x <= n; x++) {
        left_sum += x;
        if (left_sum * 2 == sum) {
            return x;
        }
    }
    return -1;
},"diGraph findPivot {

