public int ratioSubstringCount(String s, int num1, int num2) {
    int count0 = 0, count1 = 0;
    Map<Integer, Integer> frequency = new HashMap<>();
    int result = 0;

    frequency.put(0, 1);

    for (char c : s.toCharArray()) {
        if (c == '0') count0++;
        else count1++;

        int curr_diff = count0 * num2 - count1 * num1;
        result += frequency.getOrDefault(curr_diff, 0);
        frequency.put(curr_diff, frequency.getOrDefault(curr_diff, 0) + 1);
    }
    return result;
},"diGraph ratioSubstringCount {

