    total_sum = sum(skill)
    target_sum = total_sum // 2
    if total_sum % 2 == 1:
        return -1

    dp = {0: 1}
    max_chemistry = 0

    for s in skill:
        for i in range(target_sum - s, -1, -1):
            if i in dp:
