int maxValueAfterOperations(int[][] grid) {
    int ans = 0;
    while (grid.length != 0) {
        int maxVal = 0, maxRow = -1;

        for (int i = 0; i < grid.length; ++i) {
            int rowMax = Arrays.stream(grid[i]).max().getAsInt();
            if (rowMax > maxVal) {
                maxVal = rowMax;
                maxRow = i;
            }
            grid[i] = Arrays.stream(grid[i]).filter(e -> e != rowMax).toArray();
        }

        ans += maxVal;
        if (grid[maxRow].length == 0) {
            grid = Arrays.stream(grid).filter(row -> row.length != 0).toArray(int[][]::new);
        }
    }

    return ans;
},"diGraph maxValueAfterOperations {

