import java.util.HashSet;
import java.util.Set;

public int countSimilarPairs(String[] words) {
    int count = 0;
    for (int i = 0; i < words.length; ++i) {
        for (int j = i + 1; j < words.length; ++j) {
            Set<Character> set1 = new HashSet<>();
