public int kBigIndices(int[] nums, int k) {
    int n = nums.length;
    int[] left = new int[n];
    int[] right = new int[n];

    for (int i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1])
            left[i] = left[i - 1] + 1;

        int j = n - 1 - i;
        if (nums[j] < nums[j + 1])
            right[j] = right[j + 1] + 1;
    }

    int count = 0;
    for (int i = 0; i < n; i++)
        if (left[i] >= k && right[i] >= k)
            count++;

    return count;
},"diGraph kBigIndices {

