import java.util.Set;
import java.util.HashSet;

public int countDistinctPrimeFactors(int[] nums) {
    Set<Integer> prime_factors = new HashSet<>();
    for (int n : nums) {
        for (int divisor = 2; divisor * divisor <= n; ++divisor) {
            if (n % divisor == 0) {
                prime_factors.add(divisor);           
                prime_factors.add(n / divisor);
            }
        }
    }
    return prime_factors.size();
},"diGraph countDistinctPrimeFactors {

