public int min_partitions(String s, int k) {
    int n = s.length();
    int count = 0, idx = 0;

    while (idx < n) {
        int currentValue = 0;
        while (idx < n && currentValue * 10 + (s.charAt(idx) - '0') <= k) {
            currentValue = currentValue * 10 + (s.charAt(idx) - '0');
            idx++;
        }

        if (currentValue == 0) return -1;
        count++;
    }

    return count;
