public int xorBeauty(int[] nums) {
    int n = nums.length;
    int maxXOR = 1024;
    int[] counter = new int[maxXOR];

    for (int num : nums) {
        counter[num % maxXOR]++;
    }

    int xor_beauty = 0;
    for (int i = 0; i < maxXOR; i++) {
        for (int j = i; j < maxXOR; j++) {
            int k = (i | j) & (~(i ^ j));
            if (k < maxXOR && k >= j) {
                int count = counter[i] * counter[j] * (i == j ? 1 : 2);
                if (k != i && k != j) {
                    count *= counter[k];
                }
                xor_beauty ^= count;
            }
        }
    }

    return xor_beauty;
},"diGraph xorBeauty {

