public int sumOfDigits(int n) {
    int sum = 0;
    boolean positive = true;

    while (n > 0) {
        int digit = n % 10;
        n /= 10;

        if (positive) {
            sum += digit;
        } else {
            sum -= digit;
        }

        positive = !positive;
    }

    return sum;
},"diGraph sumOfDigits {

