public int minCost(int[] nums, int k) {
    int n = nums.length;
    int[] count = new int[1001], dp = new int[n + 1];
    Arrays.fill(dp, Integer.MAX_VALUE);
    dp[0] = 0;

    for (int i = 0, j = 0; j < n; ++j) {
        ++count[nums[j]];
        if (count[nums[j]] == 2)
            dp[j + 1] = dp[i] + k + (j - i + 1);
        else if (count[nums[j]] > 2)
            dp[j + 1] = Math.min(dp[j], dp[j - 1] + 1);
        else
            dp[j + 1] = dp[j] + 1;

        while (i < j + 1 && count[nums[i]] >= 2) {
            --count[nums[i]];
            ++i;
        }
    }
    return dp[n] + n * k;
},"diGraph minCost {

