public int countFairPairs(int[] nums, int lower, int upper) {
    int n = nums.length;
    int fair_pairs = 0;
    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            if ((lower <= nums[i] + nums[j]) && (nums[i] + nums[j] <= upper)) {
                fair_pairs++;
            }
        }
    }
    return fair_pairs;
},"diGraph countFairPairs {

