public int minScoreAfterChange(int[] nums) {
    int n = nums.length;
    int first_min = nums[0], second_min = nums[1], last_max = nums[n - 1], second_last_max = nums[n - 2];

    for (int i = 1; i < n - 1; i++) {
        first_min = Math.min(first_min, nums[i]);
        second_min = Math.min(second_min, nums[i + 1]);
        last_max = Math.max(last_max, nums[i]);
        second_last_max = Math.max(second_last_max, nums[i - 1]);
    }

    int low = Math.min(Math.min(first_min, last_max), Math.min(second_min, second_last_max));
    int high = Math.max(Math.max(first_min, last_max), Math.max(second_min, second_last_max));

    return high - low;
},"diGraph minScoreAfterChange {

