import java.util.HashMap;
import java.util.List;
import java.util.Map;

public List<List<Integer>> merge_nums(List<List<Integer>> nums1, List<List<Integer>> nums2) {
    Map<Integer, Integer> merged_map = new HashMap<>();;
    List<List<Integer>> merged = new ArrayList<>();

    for(List<Integer> p : nums1) {
        merged_map.put(p.get(0), merged_map.getOrDefault(p.get(0), 0) + p.get(1));
    }

    for(List<Integer> p : nums2) {
        merged_map.put(p.get(0), merged_map.getOrDefault(p.get(0), 0) + p.get(1));
    }

    for(Map.Entry<Integer, Integer> entry : merged_map.entrySet()) {
        List<Integer> tmp = new ArrayList<>();
        tmp.add(entry.getKey());
        tmp.add(entry.getValue());
        merged.add(tmp);
    }

    return merged;
},"diGraph merge_nums {

