import java.util.HashMap;

public int countSquareFreeSubsets(int[] nums) {
    HashMap<Integer, Integer> counter = new HashMap<>();
    for (int num : nums) {
        counter.put(num, counter.getOrDefault(num, 0) + 1);
    }

    long[][] dp = new long[61][1001];
    int idx = 0;
    int MOD = 1000000000 + 7;
    dp[0][0] = 1;
    for (int num : counter.keySet()) {
        int freq = counter.get(num);
        idx++;
        for (int sq = 0; sq <= 60; sq++) {
            for (int ns = 0; ns + freq <= 1000; ns++) {
                dp[idx][ns + freq] += (dp[idx - 1][ns] * ((1L << freq) - 1)) % MOD;
                dp[idx][ns + freq] %= MOD;
                dp[idx][ns] += dp[idx - 1][ns];
                dp[idx][ns] %= MOD;

                if ((sq / num) % 2 == 1) {
                    dp[idx][ns + freq] -= dp[idx - 1][ns] * ((1L << (freq - 1)) - 1) % MOD;
                    if(dp[idx][ns + freq] < 0)
                        dp[idx][ns + freq] += MOD;
                }
            }
        }
    }
    return (int)dp[idx][0];
},"diGraph countSquareFreeSubsets {

