int minSumOfTwoNumbers(String num) {
    int[] cnt = new int[10];
    for (char c : num.toCharArray()) 
        cnt[c - '0']++;

    int num1 = 0, num2 = 0;
    for (int i = 1; i <= 9; i += 2) {
        int temp = cnt[i];
        while (temp-- > 0)
            num1 = num1 * 10 + i;
    }
    for (int i = 0; i <= 9; i += 2) {
        int temp = cnt[i];
        while (temp-- > 0)
            num2 = num2 * 10 + i;
    }
    return num1 + num2;
},"diGraph minSumOfTwoNumbers {

