    for i in range(1, 10, 2):
        temp = cnt[i]
        while temp > 0:
            num1 = num1 * 10 + i
            temp -= 1
    for i in range(0, 10, 2):
        temp = cnt[i]
        while temp > 0:
            num2 = num2 * 10 + i
            temp -= 1
    return num1 + num2,"diGraph min_sum_of_two_numbers {

