class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

def kthLargestLevelSum(root, k):
    level_sums = []
    q = Queue()
    q.put(root)

    while not q.empty():
        level_sum = 0
        level_size = q.qsize()
        for i in range(level_size):
            node = q.get()
            level_sum += node.val

            if node.left:
                q.put(node.left)
            if node.right:
                q.put(node.right)

        level_sums.append(level_sum)

    level_sums.sort(reverse=True)
    return level_sums[k-1] if k <= len(level_sums) else -1,"diGraph __init__ {

