public int beautifulSubarrays(int[] nums) {
    int[] odd = new int[20];
    int[] even = new int[20];
    even[0] = 1;

    for (int num : nums) {
        boolean parity = Integer.bitCount(num) % 2 == 1;
        for (int i = 19; i >= 0; i--) {
            int mask = 1 << i;
            if ((num & mask) != 0) {
                if (parity) {
                    int temp = odd[i];
                    odd[i] = even[i];
                    even[i] = temp;
                }
                odd[i]++;
            } else {
                if (!parity) {
                    int temp = odd[i];
                    odd[i] = even[i];
                    even[i] = temp;
                }
                even[i]++;
            }
            num -= (num & mask);
        }
    }

    long ans = 0;
    for (int i = 0; i < 20; i++) ans += (long)even[i] * (even[i] - 1) / 2;
    return (int) ans;
},"diGraph beautifulSubarrays {

