    odd = [0] * 20
    even = [0] * 20
    even[0] = 1

    for num in nums:
        parity = bin(num).count('1') % 2
        for i in range(19, -1, -1):
            mask = 1 << i
            if num & mask:
                if parity:
                    odd[i], even[i] = even[i], odd[i]
                odd[i] += 1
