    int n = grid.length;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            int k = grid[i][j];
            if (k != n * n - 1 && !isValidMove(i, j, k + 1, n)) {
                return false;
            }
        }
    }
    return true;
},"diGraph isValidMove {

