import java.util.Arrays;

public int countBeautifulSubsets(int[] nums, int k) {
    Arrays.sort(nums);
    int ans = 0;
    int[] dp = new int[nums.length];
    Arrays.fill(dp, 1);
    for (int i = 0; i < nums.length; i++) {
        for (int j = 0, l = 0, r = -1; j < i; j++) {
            while (l < j && nums[j] - nums[l] >= k) l++;
            while (r + 1 < j && nums[r + 1] - nums[j] < k) r++;
            if (l <= r) dp[j] -= dp[l - 1];
            dp[j] += dp[j - 1] + 1;
            ans += dp[j];
        }
    }
    return ans;
},"diGraph countBeautifulSubsets {

