public int maxSum(int numOnes, int numZeros, int numNegOnes, int k) {
    int maxSum = 0;
    for (int i = 0; i <= k; ++i) {
        int ones = Math.min(i, numOnes);
        int negOnes = Math.min(k - i, numNegOnes);
        maxSum = Math.max(maxSum, ones - negOnes);
    }
    return maxSum;
},"diGraph maxSum {

