public int minOperations(int[] arr, int k) {
    int n = arr.length, res = Integer.MAX_VALUE;
    int[] prefix = new int[n + 1];

    for (int i = 1; i <= n; i++) {
        prefix[i] = prefix[i - 1] + arr[i - 1];
    }

    for (int i = 1; i <= n - k + 1; i++) {
        int target = (prefix[i - 1] + prefix[n] - prefix[i + k - 1] + n / k - 1) / (n / k);
        int curr_cost = 0;
        for (int j = i; j < i + k; j++) {
            curr_cost += Math.abs(arr[j - 1] - target);
        }
        res = Math.min(res, curr_cost);
    }
    return res;
},"diGraph minOperations {

