public int longestBalancedSubstring(String s) {
    int max_len = 0;
    int zeros = 0;
    int ones = 0;
    for (int i = 0; i < s.length(); ++i) {
        if (s.charAt(i) == '0') {
            zeros++;
        } else {
            ones++;
        }
        if (zeros == ones) {
            max_len = Math.max(max_len, zeros * 2);
        } else if (zeros > ones) {
            zeros = ones = 0;
        }
    }
    zeros = ones = 0;
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s.charAt(i) == '0') {
            zeros++;
        } else {
            ones++;
        }
        if (zeros == ones) {
            max_len = Math.max(max_len, zeros * 2);
        } else if (zeros < ones) {
            zeros = ones = 0;
        }
    }
    return max_len;
},"diGraph longestBalancedSubstring {

